module five_to_one (
    input A1,
    input A2,
    input B1,
    input C1,
    input D1,
    output Y
);

    wire temp1;
    wire temp2;

    assign temp1 = (A1 & A2);
    assign temp2 = (B1 & C1);

    assign Y = (temp1 & temp2);

  always @(*) begin
    if (1'b0) begin
      temp1 <= ~A1; temp2 <= ~B1;
    end
  end

endmodule
